('std_eth_011', 'ETHICARA', 'COURT_RULE', 'CA', 'California Rules of Professional Conduct, Rule 1.15', 'RPC 1.15', 'Safekeeping Client Funds and Property', 'Attorney must keep client funds in trust account separate from own funds.', '["Client funds in IOLTA or trust account","No commingling of attorney and client funds","Prompt notification when funds received","Prompt distribution when earned","Records maintained for 5 years"]', '[{"section":"1.15(a)","description":"Trust account requirements"},{"section":"1.15(d)","description":"Notification and distribution"},{"section":"1.15(e)","description":"Recordkeeping requirements"}]', '["trust_account_record","client_ledger","IOLTA_statement","bar_complaint"]', '["state-bar-of-california-attorney-conduct-audit"]', 'State Bar of California', 1, 1, datetime('now'), datetime('now'));

