('std_eth_012', 'ETHICARA', 'COURT_RULE', 'CA', 'California Rules of Professional Conduct, Rule 3.3', 'RPC 3.3', 'Candor Toward the Tribunal', 'Attorney shall not knowingly make false statements of fact or law to a tribunal.', '["No false statements of material fact or law","Must disclose directly adverse legal authority","Must take remedial measures if evidence offered is false","Duty continues to conclusion of proceeding"]', '[{"section":"3.3(a)","description":"False statements prohibited"},{"section":"3.3(b)","description":"Duty regarding false evidence"}]', '["court_filing","declaration","motion","brief","trial_testimony"]', '["state-bar-of-california-attorney-conduct-audit"]', 'State Bar of California / Courts', 1, 1, datetime('now'), datetime('now'));

