('std_pri_004', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Const. art. I, § 1', 'CA Privacy Right', 'California Constitutional Right to Privacy', 'California Constitution expressly includes privacy as an inalienable right.', '["Privacy is an inalienable right under California Constitution","Applies to both government and private actors","Must show reasonable expectation of privacy","Balancing test: privacy interest vs. countervailing interest"]', '[{"section":"Art. I, § 1","description":"Inalienable rights include privacy"}]', '["privacy_complaint","data_collection","surveillance","employment_screening"]', '[]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

