VALUES
('std_pri_005', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '47 USC § 227 (Telephone Consumer Protection Act)', 'TCPA', 'Telephone Consumer Protection Act', 'Restricts telemarketing calls, auto-dialed calls, prerecorded messages, text messages, and unsolicited faxes.', '["Prior express written consent for autodialed/prerecorded marketing calls to cell phones","National Do Not Call Registry compliance","$500 per violation ($1,500 treble for willful)","Private right of action","Opt-out mechanism required"]', '[{"section":"227(b)","description":"Autodialer and prerecorded message restrictions"},{"section":"227(c)","description":"Do Not Call provisions"},{"section":"227(b)(3)","description":"Private right of action — $500/$1,500 per violation"}]', '["telemarketing_call","text_message","robocall","TCPA_complaint"]', '[]', 'FCC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

