('std_pri_006', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '18 USC §§ 2701-2712 (Stored Communications Act)', 'SCA', 'Stored Communications Act', 'Governs access to stored electronic communications and transactional records held by third-party service providers.', '["Prohibits unauthorized access to stored communications","Law enforcement must obtain warrant for content","Service providers limited in disclosure","Civil action for violations"]', '[{"section":"2701","description":"Unlawful access to stored communications"},{"section":"2702","description":"Voluntary disclosure restrictions"},{"section":"2703","description":"Required disclosure — government access procedures"},{"section":"2707","description":"Civil action and damages"}]', '["subpoena","search_warrant","preservation_request","SCA_order"]', '[]', 'DOJ / Federal Courts', 1, 1, datetime('now'), datetime('now'));
